#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[100005]; scanf("%s",s);
        int first=-1,last=-1; // positions of first and last charge
        for(int i=0;i<N;i++) if(s[i]!='0'){first=i; break;}
        for(int i=N-1;i>=0;i--) if(s[i]!='0'){last=i; break;}
        if(first==-1){ // no charge at all
            printf("%d\n",N);
            continue;
        }
        long long ans=0;
        // process blocks between charges
        int prev=first; char prevc=s[first];
        for(int i=first+1;i<=last;i++){
            if(s[i]!='0'){
                int dist=i-prev-1;
                if(dist>0){
                    if(prevc!=s[i]){
                        if(dist%2==1) ans+=1; // odd distance leaves one neutral
                    }
                    // same sign or even distance adds nothing
                }
                prev=i; prevc=s[i];
            }
        }
        // leading and trailing zeros never add neutrals
        printf("%lld\n",ans);
    }
    return 0;
}

