import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        first = -1
        last = -1
        for i,ch in enumerate(s):
            if ch!='0':
                first=i
                break
        for i in range(N-1,-1,-1):
            if s[i]!='0':
                last=i
                break
        if first==-1:
            out.append(str(N))
            continue
        ans=0
        prev=first
        prevc=s[first]
        for i in range(first+1,last+1):
            if s[i]!='0':
                dist=i-prev-1
                if dist>0 and prevc!=s[i] and dist%2==1:
                    ans+=1
                prev=i
                prevc=s[i]
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

